# 選擇並上傳壓縮好的收案資料夾
import os, zipfile
import pandas as pd
import numpy as np
import matplotlib.pyplot as plt
from google.colab import files

uploaded = files.upload()
zip_filename = list(uploaded.keys())[0]

extract_path = "/content/my_signals"
os.makedirs(extract_path, exist_ok=True)

with zipfile.ZipFile(zip_filename, "r") as z:
    z.extractall(extract_path)

xlsx_files = []
for root, _, fs in os.walk(extract_path):
    for f in fs:
        if f.lower().endswith(".xlsx"):
            xlsx_files.append(os.path.join(root, f))

print("xlsx 檔案數 =", len(xlsx_files))
print("\n".join([os.path.basename(p) for p in xlsx_files]))

# ==================== Plot ====================
df = pd.read_excel(os.path.join(extract_path, xlsx_files[1]), engine="calamine")
signals = df.iloc[:, :6]

fig, axes = plt.subplots(6, 1, figsize=(15, 10), sharex=True)
for i, (ax, col) in enumerate(zip(axes, signals.columns)):
    ax.plot(signals[col])
    if i < 3:
        ax.set_ylabel(f"{col} (g)")
    else:
        ax.set_ylabel(f"{col} (rad/s)")

    ax.legend([col])

fig.suptitle(f"{xlsx_files[1]}")
axes[-1].set_xlabel("Time Steps (0.01 s)")
plt.tight_layout()
plt.show()

"""# Step 2: 透過插值法將訊號長度統一

不同資料因為量測時間差異，導致訊號長度不一致，進而影響模型訓練的穩定性。因此，用插值法將各筆資料轉換為相同長度，使模型專注於學習訊號本身的變化特性，避免資料受長短差異的干擾。

用數學的方式，在既有取樣點之間估計中間數值，補齊缺失或重新取樣資料，將原始長度不一的訊號映射至統一的時間尺度與資料長度。

![image.png](data:image/png;base64,)
"""

# 插值法
TARGET_LEN = 1000

X_interp_list = []
cols6_list = []
base_names = []

for fp in xlsx_files:
    df = pd.read_excel(fp, engine="calamine")
    cols6 = df.select_dtypes(include=[np.number]).columns[:6].tolist()

    X = np.zeros((TARGET_LEN, 6))
    for i, c in enumerate(cols6):
        x = df[c].to_numpy(dtype=float)
        x = x[np.isfinite(x)]
        old = np.linspace(0, 1, len(x))
        new = np.linspace(0, 1, TARGET_LEN)
        X[:, i] = np.interp(new, old, x)

    X_interp_list.append(X)
    cols6_list.append(cols6)
    base_names.append(os.path.basename(fp))

print("插值完成：", len(X_interp_list), "筆，每筆 shape =", X_interp_list[0].shape)

#==================== Plot ====================
X0 = X_interp_list[0]
cols0 = cols6_list[0]

plt.figure(figsize=(15,4))
for i in range(6):
    plt.plot(X0[:, i], label=cols0[i])
plt.title(f"{base_names[0]}")
plt.legend(ncol=3)
plt.show()

"""# Step 3: 透過Moving Average Filter (MAF)消除雜訊

移除量測訊號中的高頻雜訊與隨機波動，使訊號整體趨勢更加平滑穩定，提升後續分析、特徵提取與模型訓練的可靠性。

![image.png](data:image/png;base64,)

透過把每一點替換為前後數個訊號的平均值。藉此抑制短時間內的劇烈變化，降低高頻雜訊，同時保留訊號的主要變化趨勢。
"""

# 移動平均濾波器
WINDOW_SIZE = 5

X_smooth_list = []
for X in X_interp_list:
    Xs = np.zeros_like(X)
    for i in range(6):
        Xs[:, i] = pd.Series(X[:, i]).rolling(WINDOW_SIZE, min_periods=1).mean().to_numpy()
    X_smooth_list.append(Xs)

print("濾波完成：", len(X_smooth_list), "筆")

# ==================== Plot ====================
Xb = X_interp_list[0]
Xa = X_smooth_list[0]
cols0 = cols6_list[0]

fig, axes = plt.subplots(6, 1, figsize=(15, 10), sharex=True)

for i, (ax, col) in enumerate(zip(axes, cols0)):
    ax.plot(Xb[:, i], label="Before", alpha=0.9)
    ax.plot(Xa[:, i], label=f"After (MA={WINDOW_SIZE})", alpha=0.9)

    if i < 3:
        ax.set_ylabel(f"{col} (g)")
    else:
        ax.set_ylabel(f"{col} (rad/s)")

    ax.legend()

axes[-1].set_xlabel("Time Steps (0.01 s)")

fig.suptitle(f"{base_names[0]}")
plt.tight_layout()
plt.show()

"""# Step 4: 透過Z-Score正規化消除受測者間的差異

為避免不同受測者運動時所產生的運動訊號振幅差異，從而影響模型學習，Z-score正規化能夠將各筆訊號轉換為具有相同統計尺度的表示方式，避免個體差異或訊號振幅大小對分析結果與模型訓練造成偏差，提升整體分析的公平性與穩定性。

𝒛=(𝒙−𝝁)/𝝈

其中，𝒛為正規化後的訊號值；𝒙為原始訊號值；𝝁為原始訊號的平均值；𝝈為原始訊號的標準差。

經此轉換後，資料分布的平均值為0、標準差為1，使模型能專注於訊號的相對變化趨勢，而非數值大小本身，進而提升訓練穩定性與分析公平性。

![image.png](data:image/png;base64,)
Z-score並不改變資料分布外型，而是將平均值變為0、標準差變為1。


"""

# Z-score normalization (正規化)
X_z_list = []

for X in X_smooth_list:
    m = np.mean(X)
    s = np.std(X)
    Xz = (X - m) / s

    # 將z-score後的資料映射到[0,1]區間
    # 其目的在於對齊時序訊號與2D影像亮度值的數值範圍
    xmin = np.min(Xz)
    xmax = np.max(Xz)
    Xz_norm = (Xz - xmin) / (xmax - xmin)
    X_z_list.append(Xz_norm)

print("z-score 完成：", len(X_z_list), "筆")

# ==================== Plot ====================
Xz0 = X_z_list[0]
cols0 = cols6_list[0]

fig, axes = plt.subplots(6, 1, figsize=(15, 10), sharex=True)

for i, (ax, col) in enumerate(zip(axes, cols0)):
    ax.plot(Xz0[:, i], label=f"{col} (z-score)")

    if i < 3:
        ax.set_ylabel(f"{col} (g)")
    else:
        ax.set_ylabel(f"{col} (rad/s)")

    ax.legend()

axes[-1].set_xlabel("Time Steps (0.01 s)")
fig.suptitle(f"{base_names[0]}")
plt.tight_layout()
plt.show()

"""# Step 5: 匯出前處理後的資料並下載"""

# 匯出至左邊雲端資料夾
output_path = "/content/processed_results"
os.makedirs(output_path, exist_ok=True)

for name, cols6, Xz in zip(base_names, cols6_list, X_z_list):
    base = os.path.splitext(name)[0]
    df_out = pd.DataFrame(Xz, columns=cols6)
    df_out.to_excel(
        os.path.join(output_path, f"{base}.xlsx"),
        index=False,
        engine="xlsxwriter"
    )

print("輸出資料夾內容：", os.listdir(output_path))

# 壓縮並下載
import shutil

shutil.make_archive("/content/processed_results", "zip", "/content/processed_results")
print("已建立：/content/processed_results.zip")

